import vex
from llama_stack_client import ToolResponse

@vex.verify({
    'schema': 'https://gov.tools/irs-payment-schema.json',
    'required_fields': ['tax_id', 'amount', 'status'],
    'block_on_failure': True
})
def validate_tool_response(tool_resp: ToolResponse):
    if not tool_resp.is_valid():
        raise ValueError('Schema violation')
    return tool_resp.data

# Usage in agent loop
response = agent.call_tool('irs_verify')
validated = validate_tool_response(response)
